  2502: { name_zh: "无终恨意", desc_zh: "400生命值25护甲25魔法抗性10技能急速苦楚在与英雄的战斗状态下，每4秒对附近的敌方英雄们造成魔法伤害，并治疗自身相当于250%已造成伤害的生命值。" },
  2503: { name_zh: "黯炎火炬", desc_zh: "80法术强度600法力20技能急速邪焰伤害型技能造成额外魔法伤害，持续3秒。黯炎被你的邪焰影响的每个敌方英雄、史诗级野怪和大型野怪都会为你提供4%法术强度。" },
  2504: { name_zh: "败魔", desc_zh: "400生命值80魔法抗性100%基础生命回复法师之祸如果连续15秒没有受到魔法伤害，获得魔法护盾。" },
  2508: { name_zh: "命定灰烬", desc_zh: "30法术强度激燃伤害型技能在3秒里持续造成15额外魔法伤害。对野怪造成额外的45魔法伤害。" },
  3001: { name_zh: "薄暮法袍", desc_zh: "200生命值30护甲30魔法抗性20技能急速闪芒：在定身英雄或被定身时，使该目标和附近的所有敌方英雄受到7%伤害提升，持续5秒。神话被动：你每装备一件传说装备，就会获得 5 护甲和 魔法抗性。" },
  3002: { name_zh: "引路者", desc_zh: "250生命值40护甲4%移动速度引路在移动时，积攒至多20额外移动速度。在最大速度时：生成一条路径来使你的友方英雄们加快移动速度，数额相当于你的15%移动速度。如果你是近战英雄，你的下一次攻击还会对目标造成持续1秒的50%减速。" },
  3003: { name_zh: "大天使之杖", desc_zh: "70法术强度600法力25技能急速敬畏获得相当于1%额外法力值的法术强度。法力流 (8秒，最大5层充能)技能在命中时提供5最大法力值(对英雄时翻倍)。在360最大法力值时转变为炽天使之拥。" },
  3004: { name_zh: "魔宗", desc_zh: "35攻击力500法力15技能急速敬畏获得0额外攻击力。法力流 (8秒，最大4层)普攻和技能在命中时会提供3最大法力值(对英雄时翻倍)。在360最大法力值时转变为魔切。" },
  3005: { name_zh: "鬼蟹", desc_zh: "45移动速度墙体行走： (0秒)获得持续6秒的穿墙行走能力。在墙体内时，获得125移动速度。施放一个技能或进行攻击将结束这个效果。" },
  3006: { name_zh: "狂战士胫甲", desc_zh: "25%攻击速度45移动速度" },
  3009: { name_zh: "轻灵之靴", desc_zh: "60移动速度迅捷步将减速效果的效能降低25%。" },
  3010: { name_zh: "共生鞋鱼", desc_zh: "40移动速度虚空生物获得【强化回城】。共生在移动150000码后，变形为灵犀众魂。" },
  3011: { name_zh: "炼金科技纯化器", desc_zh: "35法术强度10%治疗和护盾强度75%基础法力回复15技能急速芙顶之毒：对英雄们造成伤害时会施加40%重伤效果，持续3秒。重伤会降低治疗效果和生命回复的效能。" },
  3012: { name_zh: "祝福圣杯", desc_zh: "200生命值50%基础法力回复和谐：每25%基础法力回复提供25%基础生命回复。“这些受祝之水仍然将它们的能量带给应得之人。”" },
  3013: { name_zh: "灵犀众魂", desc_zh: "45移动速度虚空生物获得【强化回城】。灵犀非战斗状态下获得45移动速度。" },
  3020: { name_zh: "法师之靴", desc_zh: "12法术穿透45移动速度" },
  3023: { name_zh: "生命水井坠饰", desc_zh: "150生命值25护甲5技能急速“时尚又实用。”" },
  3024: { name_zh: "冰川圆盾", desc_zh: "25护甲300法力10技能急速" },
  3026: { name_zh: "守护天使", desc_zh: "55攻击力45护甲重生你的英雄在受到致命伤害时，会在凝滞4秒后原地复活，恢复50%基础生命值和100%最大法力值。" },
